 37	
 38	import java.util.HashSet;
 39	import java.util.Set;
 40	
 41	import static io.netty.handler.codec.http.HttpHeaderNames.AUTHORIZATION;
 42	import static io.netty.handler.codec.http.HttpHeaderNames.CONTENT_LENGTH;
 43	import static io.netty.handler.codec.http.HttpHeaderNames.CONTENT_TYPE;
 44	import static io.netty.handler.codec.http.HttpHeaderNames.HOST;
 45	import static io.netty.handler.codec.http.HttpHeaderNames.LOCATION;
 46	import static io.netty.handler.codec.http.HttpHeaderNames.PROXY_AUTHORIZATION;
 47	import static org.asynchttpclient.util.HttpConstants.Methods.GET;
 48	import static org.asynchttpclient.util.HttpConstants.Methods.HEAD;
 49	import static org.asynchttpclient.util.HttpConstants.Methods.OPTIONS;
 50	import static org.asynchttpclient.util.HttpConstants.ResponseStatusCodes.FOUND_302;
 51	import static org.asynchttpclient.util.HttpConstants.ResponseStatusCodes.MOVED_PERMANENTLY_301;
 52	import static org.asynchttpclient.util.HttpConstants.ResponseStatusCodes.PERMANENT_REDIRECT_308;
 53	import static org.asynchttpclient.util.HttpConstants.ResponseStatusCodes.SEE_OTHER_303;
 54	import static org.asynchttpclient.util.HttpConstants.ResponseStatusCodes.TEMPORARY_REDIRECT_307;
 55	import static org.asynchttpclient.util.HttpUtils.followRedirect;
 56	import static org.asynchttpclient.util.MiscUtils.isNonEmpty;
 57	import static org.asynchttpclient.util.ThrowableUtil.unknownStackTrace;
 58	
 59	public class Redirect30xInterceptor {
 60	
 61	    public static final Set<Integer> REDIRECT_STATUSES = new HashSet<>();
 62	    private static final Logger LOGGER = LoggerFactory.getLogger(Redirect30xInterceptor.class);
 63	
 64	    static {
 65	        REDIRECT_STATUSES.add(MOVED_PERMANENTLY_301);
 66	        REDIRECT_STATUSES.add(FOUND_302);
 67	        REDIRECT_STATUSES.add(SEE_OTHER_303);
 68	        REDIRECT_STATUSES.add(TEMPORARY_REDIRECT_307);
 69	        REDIRECT_STATUSES.add(PERMANENT_REDIRECT_308);
 70	    }
 71	
 72	    private final ChannelManager channelManager;
 73	    private final AsyncHttpClientConfig config;
 74	    private final NettyRequestSender requestSender;
 75	    private final MaxRedirectException maxRedirectException;
 76	    private final boolean stripAuthorizationOnRedirect;
 77	
 78	    Redirect30xInterceptor(ChannelManager channelManager, AsyncHttpClientConfig config, NettyRequestSender requestSender) {
 79	        this.channelManager = channelManager;
 80	        this.config = config;
 81	        this.requestSender = requestSender;
 82	        stripAuthorizationOnRedirect = config.isStripAuthorizationOnRedirect(); // New flag
 83	        maxRedirectException = unknownStackTrace(new MaxRedirectException("Maximum redirect reached: " + config.getMaxRedirects()),
 84	                Redirect30xInterceptor.class, "exitAfterHandlingRedirect");
 85	    }
 86	
 87	    public boolean exitAfterHandlingRedirect(Channel channel, NettyResponseFuture<?> future, HttpResponse response, Request request,
 88	                                             int statusCode, Realm realm) throws Exception {
 89	
 90	        if (followRedirect(config, request)) {
 91	            if (future.incrementAndGetCurrentRedirectCount() >= config.getMaxRedirects()) {
 92	                throw maxRedirectException;
 93	
 94	            } else {
 95	                // We must allow auth handling again.
 96	                future.setInAuth(false);
 97	                future.setInProxyAuth(false);
 98	                future.setScramContext(null);
 99	
100	                String originalMethod = request.getMethod();
101	                boolean switchToGet = !originalMethod.equals(GET) &&
102	                        !originalMethod.equals(OPTIONS) &&
103	                        !originalMethod.equals(HEAD) &&
104	                        (statusCode == MOVED_PERMANENTLY_301 || statusCode == SEE_OTHER_303 || statusCode == FOUND_302 && !config.isStrict302Handling());
105	                boolean keepBody = statusCode == TEMPORARY_REDIRECT_307 || statusCode == PERMANENT_REDIRECT_308 || statusCode == FOUND_302 && config.isStrict302Handling();
106	
107	                HttpHeaders responseHeaders = response.headers();
108	                String location = responseHeaders.get(LOCATION);
109	                Uri newUri = Uri.create(future.getUri(), location);
110	                LOGGER.debug("Redirecting to {}", newUri);
111	
112	                boolean sameBase = request.getUri().isSameBase(newUri);
113	                boolean schemeDowngrade = request.getUri().isSecured() && !newUri.isSecured();
114	                boolean stripAuth = !sameBase || schemeDowngrade || stripAuthorizationOnRedirect;
115	
116	                if (stripAuth && (request.getRealm() != null || request.getHeaders().contains(AUTHORIZATION))) {
117	                    LOGGER.debug("Stripping credentials on redirect to {}", newUri);
118	                }
119	
120	                final RequestBuilder requestBuilder = new RequestBuilder(switchToGet ? GET : originalMethod)
121	                        .setChannelPoolPartitioning(request.getChannelPoolPartitioning())
122	                        .setFollowRedirect(true)
123	                        .setLocalAddress(request.getLocalAddress())
124	                        .setNameResolver(request.getNameResolver())
125	                        .setProxyServer(request.getProxyServer())
126	                        .setRealm(stripAuth ? null : request.getRealm())
127	                        .setRequestTimeout(request.getRequestTimeout());
128	
129	                if (stripAuth) {
130	                    future.setRealm(null);
131	                    future.setProxyRealm(null);
132	                }
133	
134	                if (keepBody) {
135	                    requestBuilder.setCharset(request.getCharset());
136	                    if (isNonEmpty(request.getFormParams())) {
137	                        requestBuilder.setFormParams(request.getFormParams());
138	                    } else if (request.getStringData() != null) {
139	                        requestBuilder.setBody(request.getStringData());
140	                    } else if (request.getByteData() != null) {
141	                        requestBuilder.setBody(request.getByteData());
142	                    } else if (request.getByteBufferData() != null) {
143	                        requestBuilder.setBody(request.getByteBufferData());
144	                    } else if (request.getBodyGenerator() != null) {
145	                        requestBuilder.setBody(request.getBodyGenerator());
146	                    } else if (isNonEmpty(request.getBodyParts())) {
147	                        requestBuilder.setBodyParts(request.getBodyParts());
148	                    }
149	                }
150	
151	                requestBuilder.setHeaders(propagatedHeaders(request, realm, keepBody, stripAuth));
152	
153	                // in case of a redirect from HTTP to HTTPS, future
154	                // attributes might change
155	                final boolean initialConnectionKeepAlive = future.isKeepAlive();
156	                final Object initialPartitionKey = future.getPartitionKey();
157	
158	                CookieStore cookieStore = config.getCookieStore();
159	                if (cookieStore != null) {
160	                    // Update request's cookies assuming that cookie store is already updated by Interceptors
161	                    for (Cookie cookie : cookieStore.get(newUri)) {
162	                        requestBuilder.addCookieIfUnset(cookie);
163	                    }
164	                }
165	
166	                if (sameBase) {
167	                    // we can only assume the virtual host is still valid if the baseUrl is the same
168	                    requestBuilder.setVirtualHost(request.getVirtualHost());
169	                }
170	
171	                final Request nextRequest = requestBuilder.setUri(newUri).build();
172	                future.setTargetRequest(nextRequest);
173	
174	                LOGGER.debug("Sending redirect to {}", newUri);
175	
176	                if (channel instanceof Http2StreamChannel) {
177	                    // HTTP/2 stream channels are single-use and close immediately after the response.
178	                    // No draining needed — just close the stream and send the next request.
179	                    channel.close();
180	                    requestSender.sendNextRequest(nextRequest, future);
181	                } else if (future.isKeepAlive() && !HttpUtil.isTransferEncodingChunked(response)) {
182	                    if (sameBase) {
183	                        future.setReuseChannel(true);
184	                        // we can't directly send the next request because we still have to received LastContent
185	                        requestSender.drainChannelAndExecuteNextRequest(channel, future, nextRequest);
186	                    } else {
187	                        channelManager.drainChannelAndOffer(channel, future, initialConnectionKeepAlive, initialPartitionKey);
188	                        requestSender.sendNextRequest(nextRequest, future);
189	                    }
190	
191	                } else {
192	                    // redirect + chunking = WAT
193	                    channelManager.closeChannel(channel);
194	                    requestSender.sendNextRequest(nextRequest, future);
195	                }
196	
197	                return true;
198	            }
199	        }
200	        return false;
201	    }
202	
203	    private static HttpHeaders propagatedHeaders(Request request, Realm realm, boolean keepBody, boolean stripAuthorization) {
204	        HttpHeaders headers = request.getHeaders()
205	                .remove(HOST)
206	                .remove(CONTENT_LENGTH);
207	
208	        if (!keepBody) {
209	            headers.remove(CONTENT_TYPE);
210	        }
211	
212	        if (stripAuthorization || (realm != null && (realm.getScheme() == AuthScheme.NTLM
213	                || realm.getScheme() == AuthScheme.SCRAM_SHA_256))) {
214	            headers.remove(AUTHORIZATION)
215	                    .remove(PROXY_AUTHORIZATION);
216	        }
217	        return headers;
218	    }
219	}

