 32	/**
 33	 * Tests for credential stripping on cross-domain redirects and HTTPS-to-HTTP downgrades.
 34	 * Verifies that Authorization headers and Realm credentials are not leaked to different origins.
 35	 */
 36	public class RedirectCredentialSecurityTest {
 37	
 38	    private static HttpServer serverA;
 39	    private static HttpServer serverB;
 40	    private static HttpServer serverC;
 41	    private static int portA;
 42	    private static int portB;
 43	    private static int portC;
 44	    private static final AtomicReference<String> lastAuthHeaderOnA = new AtomicReference<>();
 45	    private static final AtomicReference<String> lastAuthHeaderOnB = new AtomicReference<>();
 46	    private static final AtomicReference<String> authAtChainStep2 = new AtomicReference<>();
 47	    private static final AtomicReference<String> authOnBounceBack = new AtomicReference<>();
 48	    private static final AtomicReference<String> authOn307Target = new AtomicReference<>();
 49	    private static final AtomicReference<String> bodyOn307Target = new AtomicReference<>();
 50	    private static final AtomicReference<String> authOn308Target = new AtomicReference<>();
 51	    private static final AtomicReference<String> bodyOn308Target = new AtomicReference<>();
 52	
 53	    @BeforeAll
 54	    public static void startServers() throws Exception {
 55	        // Server A: the "origin" server that issues redirects
 56	        serverA = HttpServer.create(new InetSocketAddress("127.0.0.1", 0), 0);
 57	        portA = serverA.getAddress().getPort();
 58	
 59	        // Server B: the "target" server that receives redirected requests (different port = different origin)
 60	        serverB = HttpServer.create(new InetSocketAddress("127.0.0.1", 0), 0);
 61	        portB = serverB.getAddress().getPort();
 62	
 63	        // Server C: a third server for multi-hop redirect chains
 64	        serverC = HttpServer.create(new InetSocketAddress("127.0.0.1", 0), 0);
 65	        portC = serverC.getAddress().getPort();
 66	
 67	        // Server A endpoints
 68	        serverA.createContext("/redirect-to-b", exchange -> {
 69	            lastAuthHeaderOnA.set(exchange.getRequestHeaders().getFirst("Authorization"));
 70	            exchange.getResponseHeaders().add("Location", "http://127.0.0.1:" + portB + "/target");
 71	            exchange.sendResponseHeaders(302, -1);
 72	            exchange.close();
 73	        });
 74	
 75	        serverA.createContext("/redirect-same-origin", exchange -> {
 76	            lastAuthHeaderOnA.set(exchange.getRequestHeaders().getFirst("Authorization"));
 77	            exchange.getResponseHeaders().add("Location", "http://127.0.0.1:" + portA + "/final");
 78	            exchange.sendResponseHeaders(302, -1);
 79	            exchange.close();
 80	        });
 81	
 82	        serverA.createContext("/final", exchange -> {
 83	            lastAuthHeaderOnA.set(exchange.getRequestHeaders().getFirst("Authorization"));
 84	            exchange.sendResponseHeaders(200, 0);
 85	            exchange.getResponseBody().close();
 86	            exchange.close();
 87	        });
 88	
 89	        // Server B endpoints
 90	        serverB.createContext("/target", exchange -> {
 91	            lastAuthHeaderOnB.set(exchange.getRequestHeaders().getFirst("Authorization"));
 92	            exchange.sendResponseHeaders(200, 0);
 93	            exchange.getResponseBody().close();
 94	            exchange.close();
 95	        });
 96	
 97	        // Multi-hop: A → A (same-origin) → B (cross-domain)
 98	        serverA.createContext("/chain-same-then-cross", exchange -> {
 99	            exchange.getResponseHeaders().add("Location", "http://127.0.0.1:" + portA + "/chain-step2");
100	            exchange.sendResponseHeaders(302, -1);
101	            exchange.close();
102	        });
103	
104	        serverA.createContext("/chain-step2", exchange -> {
105	            authAtChainStep2.set(exchange.getRequestHeaders().getFirst("Authorization"));
106	            exchange.getResponseHeaders().add("Location", "http://127.0.0.1:" + portB + "/target");
107	            exchange.sendResponseHeaders(302, -1);
108	            exchange.close();
109	        });
110	
111	        // Multi-hop: A → B (cross-domain, credentials stripped) → C (credentials stay stripped)
112	        serverA.createContext("/chain-cross-and-back", exchange -> {
113	            exchange.getResponseHeaders().add("Location", "http://127.0.0.1:" + portB + "/bounce-to-c");
114	            exchange.sendResponseHeaders(302, -1);
115	            exchange.close();
116	        });
117	
118	        serverB.createContext("/bounce-to-c", exchange -> {
119	            exchange.getResponseHeaders().add("Location", "http://127.0.0.1:" + portC + "/chain-final");
120	            exchange.sendResponseHeaders(302, -1);
121	            exchange.close();
122	        });
123	
124	        serverC.createContext("/chain-final", exchange -> {
125	            authOnBounceBack.set(exchange.getRequestHeaders().getFirst("Authorization"));
126	            exchange.sendResponseHeaders(200, 0);
127	            exchange.getResponseBody().close();
128	            exchange.close();
129	        });
130	
131	        // 307 Temporary Redirect: A → B (body preserved, auth stripped)
132	        serverA.createContext("/redirect-307-to-b", exchange -> {
133	            exchange.getResponseHeaders().add("Location", "http://127.0.0.1:" + portB + "/target-307");
134	            exchange.sendResponseHeaders(307, -1);
135	            exchange.close();
136	        });
137	
138	        serverB.createContext("/target-307", exchange -> {
139	            authOn307Target.set(exchange.getRequestHeaders().getFirst("Authorization"));
140	            bodyOn307Target.set(new String(exchange.getRequestBody().readAllBytes(), StandardCharsets.UTF_8));
141	            exchange.sendResponseHeaders(200, 0);
142	            exchange.getResponseBody().close();
143	            exchange.close();
144	        });
145	
146	        // 308 Permanent Redirect: A → B (body preserved, auth stripped)
147	        serverA.createContext("/redirect-308-to-b", exchange -> {
148	            exchange.getResponseHeaders().add("Location", "http://127.0.0.1:" + portB + "/target-308");
149	            exchange.sendResponseHeaders(308, -1);
150	            exchange.close();
151	        });
152	
153	        serverB.createContext("/target-308", exchange -> {
154	            authOn308Target.set(exchange.getRequestHeaders().getFirst("Authorization"));
155	            bodyOn308Target.set(new String(exchange.getRequestBody().readAllBytes(), StandardCharsets.UTF_8));
156	            exchange.sendResponseHeaders(200, 0);
157	            exchange.getResponseBody().close();
158	            exchange.close();
159	        });
160	
161	        serverA.start();
162	        serverB.start();
163	        serverC.start();
164	    }
165	
166	    @AfterAll
167	    public static void stopServers() {
168	        serverA.stop(0);
169	        serverB.stop(0);
170	        serverC.stop(0);
171	    }
