173	    /**
174	     * Cross-domain redirect (different port) must strip Authorization header.
175	     */
176	    @Test
177	    void crossDomainRedirectStripsAuthHeader() throws Exception {
178	        DefaultAsyncHttpClientConfig config = new DefaultAsyncHttpClientConfig.Builder()
179	                .setFollowRedirect(true)
180	                .build();
181	        try (DefaultAsyncHttpClient client = new DefaultAsyncHttpClient(config)) {
182	            lastAuthHeaderOnA.set(null);
183	            lastAuthHeaderOnB.set(null);
184	
185	            client.prepareGet("http://127.0.0.1:" + portA + "/redirect-to-b")
186	                    .setHeader("Authorization", "Bearer secret-token")
187	                    .execute()
188	                    .get(5, TimeUnit.SECONDS);
189	
190	            // Auth header should be present on the original request to server A
191	            assertEquals("Bearer secret-token", lastAuthHeaderOnA.get(),
192	                    "Authorization header should be present on original request");
193	            // Auth header must NOT be forwarded to the cross-domain target (server B)
194	            assertNull(lastAuthHeaderOnB.get(),
195	                    "Authorization header must be stripped on cross-domain redirect");
196	        }
197	    }
198	
199	    /**
200	     * Same-origin redirect (same host and port) should preserve Authorization header.
201	     */
202	    @Test
203	    void sameOriginRedirectPreservesAuthHeader() throws Exception {
204	        DefaultAsyncHttpClientConfig config = new DefaultAsyncHttpClientConfig.Builder()
205	                .setFollowRedirect(true)
206	                .build();
207	        try (DefaultAsyncHttpClient client = new DefaultAsyncHttpClient(config)) {
208	            lastAuthHeaderOnA.set(null);
209	
210	            client.prepareGet("http://127.0.0.1:" + portA + "/redirect-same-origin")
211	                    .setHeader("Authorization", "Bearer secret-token")
212	                    .execute()
213	                    .get(5, TimeUnit.SECONDS);
214	
215	            // Auth header should still be present after same-origin redirect
216	            assertEquals("Bearer secret-token", lastAuthHeaderOnA.get(),
217	                    "Authorization header should be preserved on same-origin redirect");
218	        }
219	    }
220	
221	    /**
222	     * Cross-domain redirect must strip Proxy-Authorization header too.
223	     */
224	    @Test
225	    void crossDomainRedirectStripsProxyAuthHeader() throws Exception {
226	        DefaultAsyncHttpClientConfig config = new DefaultAsyncHttpClientConfig.Builder()
227	                .setFollowRedirect(true)
228	                .build();
229	        try (DefaultAsyncHttpClient client = new DefaultAsyncHttpClient(config)) {
230	            lastAuthHeaderOnB.set(null);
231	
232	            // We capture Proxy-Authorization on server B using a custom handler
233	            final AtomicReference<String> proxyAuthOnB = new AtomicReference<>();
234	            serverB.createContext("/target-proxy", exchange -> {
235	                proxyAuthOnB.set(exchange.getRequestHeaders().getFirst("Proxy-Authorization"));
236	                exchange.sendResponseHeaders(200, 0);
237	                exchange.getResponseBody().close();
238	                exchange.close();
239	            });
240	            serverA.createContext("/redirect-to-b-proxy", exchange -> {
241	                exchange.getResponseHeaders().add("Location", "http://127.0.0.1:" + portB + "/target-proxy");
242	                exchange.sendResponseHeaders(302, -1);
243	                exchange.close();
244	            });
245	
246	            client.prepareGet("http://127.0.0.1:" + portA + "/redirect-to-b-proxy")
247	                    .setHeader("Proxy-Authorization", "Basic cHJveHk6cGFzcw==")
248	                    .execute()
249	                    .get(5, TimeUnit.SECONDS);
250	
251	            assertNull(proxyAuthOnB.get(),
252	                    "Proxy-Authorization header must be stripped on cross-domain redirect");
253	        }
254	    }
