 45	    public Uri(String scheme, @Nullable String userInfo, String host, int port, String path, @Nullable String query, @Nullable String fragment) {
 46	        this.scheme = assertNotEmpty(scheme, "scheme");
 47	        this.userInfo = userInfo;
 48	        this.host = assertNotEmpty(host, "host");
 49	        this.port = port;
 50	        this.path = path;
 51	        this.query = query;
 52	        this.fragment = fragment;
 53	        secured = HTTPS.equals(scheme) || WSS.equals(scheme);
 54	        webSocket = WS.equals(scheme) || WSS.equalsIgnoreCase(scheme);
 55	    }
