 61	    public static Uri create(@Nullable Uri context, final String originalUrl) {
 62	        UriParser parser = UriParser.parse(context, originalUrl);
 63	        if (isEmpty(parser.scheme)) {
 64	            throw new IllegalArgumentException(originalUrl + " could not be parsed into a proper Uri, missing scheme");
 65	        }
 66	        if (isEmpty(parser.host)) {
 67	            throw new IllegalArgumentException(originalUrl + " could not be parsed into a proper Uri, missing host");
 68	        }
 69	
 70	        return new Uri(parser.scheme, parser.userInfo, parser.host, parser.port, parser.path, parser.query, parser.fragment);
 71	    }
