121	    public String toUrl() {
122	        if (url == null) {
123	            StringBuilder sb = StringBuilderPool.DEFAULT.stringBuilder();
124	            sb.append(scheme).append("://");
125	            if (userInfo != null) {
126	                sb.append(userInfo).append('@');
127	            }
128	            sb.append(host);
129	            if (port != -1) {
130	                sb.append(':').append(port);
131	            }
132	            if (path != null) {
133	                sb.append(path);
134	            }
135	            if (query != null) {
136	                sb.append('?').append(query);
137	            }
138	            url = sb.toString();
139	            sb.setLength(0);
140	        }
141	        return url;
142	    }
