144	    /**
145	     * @return [scheme]://[hostname](:[port])/path. Port is omitted if it matches the scheme's default one.
146	     */
147	    public String toBaseUrl() {
148	        StringBuilder sb = StringBuilderPool.DEFAULT.stringBuilder();
149	        sb.append(scheme).append("://").append(host);
150	        if (port != -1 && port != getSchemeDefaultPort()) {
151	            sb.append(':').append(port);
152	        }
153	        if (isNonEmpty(path)) {
154	            sb.append(path);
155	        }
156	        return sb.toString();
157	    }
158	
159	    public String toRelativeUrl() {
160	        StringBuilder sb = StringBuilderPool.DEFAULT.stringBuilder();
161	        if (isNonEmpty(path)) {
162	            sb.append(path);
163	        } else {
164	            sb.append('/');
165	        }
166	        if (query != null) {
167	            sb.append('?').append(query);
168	        }
169	
170	        return sb.toString();
171	    }
