160	    // Take partition key lock object,
161	    // but do not release channel lock.
162	    public Object takePartitionKeyLock() {
163	        // shortcut, much faster than getAndSet
164	        if (partitionKeyLock == null) {
165	            return null;
166	        }
167	
168	        return PARTITION_KEY_LOCK_FIELD.getAndSet(this, null);
169	    }
