183	    @Override
184	    public boolean cancel(boolean force) {
185	        releasePartitionKeyLock();
186	        cancelTimeouts();
187	
188	        if (IS_CANCELLED_FIELD.getAndSet(this, 1) != 0) {
189	            return false;
190	        }
191	
192	        final Channel ch = channel; //atomic read, so that it won't end up in TOCTOU
193	        if (ch != null) {
194	            Channels.setDiscard(ch);
195	            Channels.silentlyCloseChannel(ch);
196	        }
197	
198	        if (ON_THROWABLE_CALLED_FIELD.getAndSet(this, 1) == 0) {
199	            try {
200	                asyncHandler.onThrowable(new CancellationException());
201	            } catch (Throwable t) {
202	                LOGGER.warn("cancel", t);
203	            }
204	        }
205	
206	        future.cancel(false);
207	        return true;
208	    }
