506	    public void acquirePartitionLockLazily() throws IOException {
507	        if (connectionSemaphore == null || partitionKeyLock != null) {
508	            return;
509	        }
510	
511	        Object partitionKey = getPartitionKey();
512	        connectionSemaphore.acquireChannelLock(partitionKey);
513	        Object prevKey = PARTITION_KEY_LOCK_FIELD.getAndSet(this, partitionKey);
514	        if (prevKey != null) {
515	            // self-check
516	
517	            connectionSemaphore.releaseChannelLock(prevKey);
518	            releasePartitionKeyLock();
519	
520	            throw new IllegalStateException("Trying to acquire partition lock concurrently. Please report.");
521	        }
522	
523	        if (isDone()) {
524	            // may be cancelled while we acquired a lock
525	            releasePartitionKeyLock();
526	        }
527	    }
